mapper.select:
select 
from ebay_price_tracking_snapshot s
left join ebay_product_dedup d on s.site = d.site and s.sku = d.sku

    and s.current_flag = 1



            and s.site in #{it}
            and s.site like concat('%', #{site}, '%')



        and s.sku like concat('%', #{sku}, '%')


        and s.product_name like concat('%', #{productName}, '%')


        and s.brand_code like concat('%', #{brandCode}, '%')


        and s.operator_name like concat('%', #{operatorName}, '%')


        and s.sku_level = #{skuLevel}





                and s.our_lowest_price between #{our_lowest_price_val} and #{our_lowest_price_val2}

             and s.our_lowest_price is null 
             and s.our_lowest_price is not null 
             and s.our_lowest_price ${our_lowest_price_op} #{our_lowest_price_val} 





                and s.tracking_price between #{tracking_price_val} and #{tracking_price_val2}

             and s.tracking_price is null 
             and s.tracking_price is not null 
             and s.tracking_price ${tracking_price_op} #{tracking_price_val} 





                and s.tracking_profit_margin between #{tracking_profit_margin_val} and #{tracking_profit_margin_val2}

             and s.tracking_profit_margin is null 
             and s.tracking_profit_margin is not null 
             and s.tracking_profit_margin ${tracking_profit_margin_op} #{tracking_profit_margin_val} 





                and s.floor_price between #{floor_price_val} and #{floor_price_val2}

             and s.floor_price is null 
             and s.floor_price is not null 
             and s.floor_price ${floor_price_op} #{floor_price_val} 





                and s.return_rate between #{return_rate_val} and #{return_rate_val2}

             and s.return_rate is null 
             and s.return_rate is not null 
             and s.return_rate ${return_rate_op} #{return_rate_val} 





                and s.sales_3d between #{sales_3d_val} and #{sales_3d_val2}

             and s.sales_3d is null 
             and s.sales_3d is not null 
             and s.sales_3d ${sales_3d_op} #{sales_3d_val} 





                and s.sales_7d between #{sales_7d_val} and #{sales_7d_val2}

             and s.sales_7d is null 
             and s.sales_7d is not null 
             and s.sales_7d ${sales_7d_op} #{sales_7d_val} 





                and s.sales_30d between #{sales_30d_val} and #{sales_30d_val2}

             and s.sales_30d is null 
             and s.sales_30d is not null 
             and s.sales_30d ${sales_30d_op} #{sales_30d_val} 





                and s.sales_90d between #{sales_90d_val} and #{sales_90d_val2}

             and s.sales_90d is null 
             and s.sales_90d is not null 
             and s.sales_90d ${sales_90d_op} #{sales_90d_val} 





                and s.max_monthly_sales between #{max_monthly_sales_val} and #{max_monthly_sales_val2}

             and s.max_monthly_sales is null 
             and s.max_monthly_sales is not null 
             and s.max_monthly_sales ${max_monthly_sales_op} #{max_monthly_sales_val} 





                and s.overseas_stock between #{overseas_stock_val} and #{overseas_stock_val2}

             and s.overseas_stock is null 
             and s.overseas_stock is not null 
             and s.overseas_stock ${overseas_stock_op} #{overseas_stock_val} 





                and s.overseas_stock_age_days between #{overseas_stock_age_days_val} and #{overseas_stock_age_days_val2}

             and s.overseas_stock_age_days is null 
             and s.overseas_stock_age_days is not null 
             and s.overseas_stock_age_days ${overseas_stock_age_days_op} #{overseas_stock_age_days_val} 





                and s.stock_sales_ratio between #{stock_sales_ratio_val} and #{stock_sales_ratio_val2}

             and s.stock_sales_ratio is null 
             and s.stock_sales_ratio is not null 
             and s.stock_sales_ratio ${stock_sales_ratio_op} #{stock_sales_ratio_val} 





                and s.estimated_replenish_qty between #{estimated_replenish_qty_val} and #{estimated_replenish_qty_val2}

             and s.estimated_replenish_qty is null 
             and s.estimated_replenish_qty is not null 
             and s.estimated_replenish_qty ${estimated_replenish_qty_op} #{estimated_replenish_qty_val} 




    order by s.site
    order by s.sku
    order by s.sales_3d
    order by s.sales_7d
    order by s.sales_30d
    order by s.sales_90d
    order by s.max_monthly_sales
    order by s.overseas_stock
    order by s.overseas_stock_age_days
    order by s.stock_sales_ratio
    order by s.estimated_replenish_qty
    order by s.our_lowest_price
    order by s.tracking_price
    order by s.tracking_profit_margin
    order by s.floor_price
    order by s.return_rate
    order by s.site, s.sku

ascdesc
